WHERE NOT EXISTS (SELECT 1 FROM words w WHERE w.word = v.word);

--rollback DELETE FROM words WHERE word IN ('family','parent','father','mother','brother','sister','son','daughter','husband','wife','grandfather','grandmother','uncle','aunt','cousin','friend','neighbor','person','man','woman','child','baby','boy','girl','talk','listen','look','see','hear','think','know','want','like','love','hate','feel','try','start','stop','wait','help','work','play','study','performance','exhibition','orchestra','sculpture','photography','literature','novel','poetry','musician','actress','director','audience','critic','entertain','inspire','creative','artistic','inflation','recession','gross domestic product','monopoly','commodity','depreciation','subsidy','fiscal','monetary','austerity','metabolism','genome','neuroscience','pathogen','catalyst','phenomenon','hypothesis','quantum','gravity','entropy');
